const stdout = $input.first().json.stdout;

if (!stdout) {
  return [{ json: { response: "", rc: 0, salvaged: "no" } }];
}

const lines = stdout.split("\n").filter(l => l.trim()).map(l => {
  try { return JSON.parse(l); } catch { return null; }
}).filter(l => l !== null);

// Extract runner_meta (rc/salvaged signals from the shell)
const metaItem = lines.filter(item => item.type === "runner_meta").pop();
const rc = metaItem ? Number(metaItem.rc) || 0 : 0;
const salvaged = metaItem ? String(metaItem.salvaged || "no") : "no";

// Prefer text-type messages (last one wins, as before)
const textItem = lines.filter(item => item.type === "text").pop();
if (textItem && textItem.part && textItem.part.text) {
  return [{ json: { response: textItem.part.text, rc, salvaged } }];
}

// Fall back to error-type messages so infra failures are surfaced
const errorItem = lines.filter(item => item.type === "error").pop();
if (errorItem && errorItem.error) {
  const msg = errorItem.error.data?.message || errorItem.error.name || JSON.stringify(errorItem.error);
  return [{ json: { response: `[opencode error] ${msg}`, rc, salvaged } }];
}

return [{ json: { response: "", rc, salvaged } }];
